import Metrics from '@byted-service/metrics';
export interface LogAgentMessageType {
    /**
     * 日志信息
     */
    msg: string;
    /**
     * 日志的主要tags，定义可见：https://docs.bytedance.net/doc/uhnP66an8j3qU0mn2Kjywd
     * 你可以传入这些tag来覆盖默认值，目前会写入的字段包括：
     * ```
     * _taskName: 通常使用psm或rpc
     * _ts: 日志时间
     * _level: 日志的级别，默认为info
     * _location: 日志来源
     * _language: 应用使用的编程语言，默认为js
     * _psm: 应用的psm
     * _cluster: 应用所在cluster
     * _logid: 默认为0
     * _stage: 应用的stage，用来区分小流量等环境
     * _podName: tce实例的podname字段
     * ```
     */
    tags?: {
        [key: string]: any;
    };
}
export interface LogAgentOptionsType {
    /**
     * 应用的psm，在进行日志记录时会将覆盖应用的_psm字段；如果没有指定_taskName的话，则会覆盖_taskName。
     */
    psm?: string;
    /**
     * 发送日志的间隔时间，默认为10240ms；如果需要发送的日志长度没有超过maxLen，则logagent会每隔sendInterval的时间发送一次日志。
     */
    sendInterval?: number;
    /**
     * 累计日志的长度，默认为64KB(64 * 1024)；当需要发送的日志长度超过最大值时，logagent会立即发送日志。
     */
    maxLen?: number;
    /**
     * 内部测试用，外部不要直接使用
     */
    host?: string;
    /**
     * 内部测试用，外部不要直接使用
     */
    port?: number;
    /**
     * 内部测试用，外部不要直接使用
     */
    socketPath?: string;
    logger?: ILogger;
    metrics?: Metrics;
}
export interface LogagentV2Options {
    psm?: string;
    flushInterval?: number;
    maxLength?: number;
    host?: string;
    port?: number;
    socketPath?: string;
    logger?: ILogger;
    metrics?: Metrics;
}
export interface Message {
    data: Uint8Array;
    tags: {
        [key: string]: string | number | undefined;
    };
    originMsg: LogAgentMessageType;
}
export interface ILogger {
    fatal(message: string, ...splat: any[]): void;
    error(message: string, ...splat: any[]): void;
    warn(message: string, ...splat: any[]): void;
    info(message: string, ...splat: any[]): void;
    debug(message: string, ...splat: any[]): void;
    trace(message: string, ...splat: any[]): void;
}
